using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "Application Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration including feature flags and service endpoints.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = "Production",
            Version = "1.0.0",
            Features = new
            {
                DarkMode = true,
                BetaAccess = false,
                MaxUploadSizeMb = 50
            },
            Services = new
            {
                DatabaseUrl = "postgres://db.example.com:5432/app",
                CacheUrl = "redis://cache.example.com:6379",
                ApiBaseUrl = "https://api.example.com/v2"
            }
        };

        return JsonSerializer.Serialize(config, JsonOptions);
    }

    [McpServerResource(
        UriTemplate = "config://app/limits",
        Name = "Rate Limits",
        MimeType = "application/json"),
     Description("Returns the configured rate limits for API endpoints.")]
    public static string GetRateLimits()
    {
        var limits = new
        {
            Global = new { RequestsPerMinute = 1000, BurstSize = 50 },
            PerUser = new { RequestsPerMinute = 100, BurstSize = 20 },
            Endpoints = new[]
            {
                new { Path = "/api/search", RequestsPerMinute = 30 },
                new { Path = "/api/upload", RequestsPerMinute = 10 },
                new { Path = "/api/export", RequestsPerMinute = 5 }
            }
        };

        return JsonSerializer.Serialize(limits, JsonOptions);
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool(ReadOnly = true), Description("Look up the value of a specific configuration key by name.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g., 'Environment', 'MaxUploadSizeMb')")] string key)
    {
        var configStore = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase)
        {
            ["Environment"] = "Production",
            ["Version"] = "1.0.0",
            ["DarkMode"] = true,
            ["BetaAccess"] = false,
            ["MaxUploadSizeMb"] = 50,
            ["DatabaseUrl"] = "postgres://db.example.com:5432/app",
            ["CacheUrl"] = "redis://cache.example.com:6379",
            ["ApiBaseUrl"] = "https://api.example.com/v2"
        };

        if (configStore.TryGetValue(key, out var value))
            return JsonSerializer.Serialize(new { Key = key, Value = value }, JsonOptions);

        return JsonSerializer.Serialize(
            new { Key = key, Error = "Key not found", AvailableKeys = configStore.Keys },
            JsonOptions);
    }

    [McpServerTool(ReadOnly = true), Description("Validate whether a feature flag is currently enabled.")]
    public static string CheckFeatureFlag(
        [Description("The feature flag name to check (e.g., 'DarkMode', 'BetaAccess')")] string flagName)
    {
        var flags = new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase)
        {
            ["DarkMode"] = true,
            ["BetaAccess"] = false,
            ["MaintenanceMode"] = false,
            ["NewOnboarding"] = true
        };

        if (flags.TryGetValue(flagName, out var enabled))
            return JsonSerializer.Serialize(new { Flag = flagName, Enabled = enabled }, JsonOptions);

        return JsonSerializer.Serialize(
            new { Flag = flagName, Error = "Flag not found", AvailableFlags = flags.Keys },
            JsonOptions);
    }
}

